// Dependency-free OpenAI-compatible proxy for a gnosis fat-station.
// Bridges POST /v1/chat/completions -> fat-station /tokenize -> /generate -> /detokenize.
// No workspace deps (node:http + global fetch only), so it runs without a bootstrapped
// pnpm workspace — unlike the full agentic openai-server.ts (which needs @a0n/* packages).
//
//   FAT_STATION_URL=http://127.0.0.1:8090 PORT=8080 MODEL_NAME=qwen05-dense node openai-proxy.mjs
import http from 'node:http';

const FAT = process.env.FAT_STATION_URL || 'http://127.0.0.1:8090';
const PORT = Number(process.env.PORT || 8080);
const MODEL = process.env.MODEL_NAME || 'qwen05-dense';
const CHATML = (process.env.CHAT_TEMPLATE || 'chatml') === 'chatml';
// Set PROXY_DEBUG=1 to log coalescer batch sizes (the embed-batching health signal).
const DEBUG = !!process.env.PROXY_DEBUG;

// timeoutMs fails the call fast when the fat-station's HTTP threads are saturated
// by long forwards: cheap calls like /tokenize otherwise queue behind 14s batches
// and the whole request hangs 24s+ before the admission gate can shed it.
async function fpost(path, body, timeoutMs = 0) {
  const r = await fetch(FAT + path, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(body),
    ...(timeoutMs ? { signal: AbortSignal.timeout(timeoutMs) } : {}),
  });
  if (!r.ok) throw new Error(`${path} -> ${r.status} ${await r.text()}`);
  return r.json();
}
// Short fail-fast budget for the ungated /tokenize hop (env-tunable). Under load,
// abort fast -> the request 429s in seconds instead of hanging behind the forwards.
const TOKENIZE_TIMEOUT_MS = Number(process.env.PROXY_TOKENIZE_TIMEOUT_MS || 4000);

// Binary POST: body is a Buffer, reply is parsed as LE f32. Used for the
// fat-station /hidden-embed embedding path (packed-u32 token ids in, f32 out).
async function fpostBinary(path, buf) {
  const r = await fetch(FAT + path, {
    method: 'POST',
    headers: { 'content-type': 'application/octet-stream' },
    body: buf,
  });
  if (!r.ok) throw new Error(`${path} -> ${r.status} ${await r.text()}`);
  return new Float32Array(await r.arrayBuffer());
}

// ── FOIL-style admission gate (re-adds the antiqueue backpressure this proxy
// bypasses) ───────────────────────────────────────────────────────────────────
// The fat-station holds a GLOBAL pipeline mutex for the entire forward
// (fat-station.rs handle_hidden_embed / handle_generate), so it runs ONE forward
// at a time. The protocol69 antiqueue/FOIL path normally paces + load-sheds work
// before it reaches the station; this OpenAI proxy calls /hidden-embed & /generate
// DIRECTLY, so concurrent HTTP requests pile onto that mutex unbounded -> wait
// times climb (1.2s -> 100s+) -> /health stops responding -> effective hang.
// Re-impose admission here: serialize forwards to PROXY_MAX_INFLIGHT (the station
// can only do 1 at a time anyway) and SHED AT ADMISSION with a 429 — the only way
// to stop wedging. A deep fixed queue does NOT prevent the wedge: with CPU embeds
// running 10-40s each, even 8 queued requests = minutes of held connections that
// look like a hang. Instead we estimate the PROJECTED wait (jobs ahead × measured
// forward time, EWMA) and reject NOW if admitting would blow past the deadline, so
// the client gets a fast 429 + retry-after and comes back, rather than a hung socket.
const GATE_MAX_INFLIGHT = Number(process.env.PROXY_MAX_INFLIGHT || 1);
// Hard backstop on queue depth; the adaptive deadline below is the real limiter.
const GATE_MAX_QUEUE = Number(process.env.PROXY_MAX_QUEUE || 16);
// Reject at admission if the projected wait would exceed this (ms). Tune to how
// long a caller will tolerate before a retry is cheaper than waiting.
const GATE_WAIT_DEADLINE_MS = Number(process.env.PROXY_WAIT_DEADLINE_MS || 20000);
let gateInflight = 0;
const gateQueue = [];
// Adaptive estimate of one forward's wall time; seeded, then EWMA'd from reality.
let ewmaForwardMs = Number(process.env.PROXY_FORWARD_MS_HINT || 8000);
class Overloaded extends Error {
  constructor(msg) {
    super(msg || 'fat-station overloaded: shedding at admission');
    this.statusCode = 429;
  }
}
function admit(fn) {
  return new Promise((resolve, reject) => {
    const ahead = gateInflight + gateQueue.length; // forwards that must finish first
    const projected = ahead * ewmaForwardMs;
    // Shed at admission: reject before enqueuing if we'd wedge (projected wait past
    // the deadline once a slot is busy) or hit the hard backstop. This is what keeps
    // the node from melting — clients get honest, fast backpressure.
    if ((ahead >= GATE_MAX_INFLIGHT && projected > GATE_WAIT_DEADLINE_MS) || gateQueue.length >= GATE_MAX_QUEUE) {
      return reject(new Overloaded(`overloaded: ~${Math.round(projected / 1000)}s projected wait (${ahead} ahead, ~${Math.round(ewmaForwardMs)}ms/forward)`));
    }
    const run = () => {
      gateInflight++;
      const t0 = Date.now();
      Promise.resolve()
        .then(fn)
        .then(resolve, reject)
        .finally(() => {
          const dt = Date.now() - t0;
          // Adapt to real latency so the shed tightens as the station slows down.
          ewmaForwardMs = 0.7 * ewmaForwardMs + 0.3 * dt;
          gateInflight--;
          const next = gateQueue.shift();
          if (next) next();
        });
    };
    if (gateInflight < GATE_MAX_INFLIGHT) run();
    else gateQueue.push(run);
  });
}

// Cheap pre-check that mirrors admit()'s rejection condition, so a handler can shed
// BEFORE doing work (e.g. /tokenize). /tokenize is "ungated" but still hits the busy
// fat-station HTTP server, so under load a doomed request would otherwise wait a full
// forward (~seconds) just to be 429'd. Pre-checking turns that into an instant shed.
// (Advisory only — admit() still enforces; this just avoids wasted tokenize work.)
function wouldShed() {
  const ahead = gateInflight + gateQueue.length;
  return (ahead >= GATE_MAX_INFLIGHT && ahead * ewmaForwardMs > GATE_WAIT_DEADLINE_MS) || gateQueue.length >= GATE_MAX_QUEUE;
}

// ── Request coalescer (micro-batching) ─────────────────────────────────────────
// Concurrent /v1/embeddings requests (and multi-input arrays) each tokenize their
// own text cheaply, then enqueue the token ids here. Over a short window (or until
// PROXY_MAX_BATCH sequences accumulate) we pack ALL pending sequences into ONE
// /hidden-embed-batch forward and fan the result rows back to each caller. The
// whole batch is a single admit()ed forward, so the GATE_MAX_INFLIGHT/QUEUE
// backpressure floor still applies — coalescing only raises throughput per forward.
const BATCH_WINDOW_MS = Number(process.env.PROXY_BATCH_WINDOW_MS || 8);
// Coalescing is only a WIN when the station has a weight-amortizing /hidden-embed-batch
// (one forward for the whole batch). Until then the fallback loops singles
// SEQUENTIALLY, which just hides concurrent load from the admission gate (the gate
// sees one batch = one unit) and serializes it into a long tail instead of shedding.
// So default MAX_BATCH=1 (each forward is its own admission unit → the gate sheds
// per-request, the antiqueue behavior we want) UNTIL we confirm at startup that the
// station has /hidden-embed-batch — see probeBatchEndpoint() below, which auto-bumps
// this to PROXY_MAX_BATCH_AUTO (32) when the weight-amortized forward is available.
// An explicit PROXY_MAX_BATCH always wins (set it to pin a value or force 1).
const MAX_BATCH_ENV = process.env.PROXY_MAX_BATCH;
const MAX_BATCH_AUTO = Number(process.env.PROXY_MAX_BATCH_AUTO || 32);
let MAX_BATCH = MAX_BATCH_ENV != null ? Number(MAX_BATCH_ENV) : 1;
let pending = []; // { tokens:number[], resolve, reject }
let batchTimer = null;

// Pack pending sequences into the /hidden-embed-batch wire format:
//   [u32 count] then count × ( [u32 token_count][token_count × u32 token_id] )
function packBatch(items) {
  let bytes = 4; // leading count
  for (const it of items) bytes += 4 + it.tokens.length * 4;
  const buf = Buffer.alloc(bytes);
  let o = 0;
  buf.writeUInt32LE(items.length >>> 0, o); o += 4;
  for (const it of items) {
    buf.writeUInt32LE(it.tokens.length >>> 0, o); o += 4;
    for (let j = 0; j < it.tokens.length; j++) { buf.writeUInt32LE(it.tokens[j] >>> 0, o); o += 4; }
  }
  return buf;
}

// Pack one sequence's token ids into the single /hidden-embed wire format (raw LE
// u32). Used by the fallback below.
function packSingle(tokens) {
  const buf = Buffer.alloc(tokens.length * 4);
  for (let j = 0; j < tokens.length; j++) buf.writeUInt32LE(tokens[j] >>> 0, j * 4);
  return buf;
}

// Run a batch on the station: try /hidden-embed-batch (one forward, amortized), and
// if the station doesn't have that endpoint yet (404) fall back to looping single
// /hidden-embed calls. This makes the coalescing proxy deployable BEFORE the batched
// fat-station handler ships, and light up the fast path automatically once it does.
async function stationEmbedBatch(items) {
  let reply;
  try {
    reply = await fpostBinary('/hidden-embed-batch', packBatch(items));
  } catch (e) {
    if (e && /-> 404\b/.test(String(e.message))) {
      const rows = [];
      for (const it of items) rows.push(Array.from(await fpostBinary('/hidden-embed', packSingle(it.tokens))));
      return rows;
    }
    throw e;
  }
  const count = items.length;
  if (reply.length % count !== 0) {
    throw new Error(`/hidden-embed-batch reply (${reply.length} f32) not divisible by batch count ${count}`);
  }
  const hidden = reply.length / count;
  // hidden of 0 means the station returned no rows -> count mismatch (don't mis-map).
  if (hidden === 0) throw new Error(`/hidden-embed-batch returned 0 rows for batch count ${count}`);
  const rows = [];
  for (let i = 0; i < count; i++) rows.push(Array.from(reply.subarray(i * hidden, (i + 1) * hidden)));
  return rows;
}

async function flush() {
  if (batchTimer) { clearTimeout(batchTimer); batchTimer = null; }
  const batch = pending;
  pending = [];
  if (!batch.length) return;
  // Observability: batch size is the whole game. A healthy multi-input request
  // should log one flush at its full size (e.g. 16/32), NOT a run of size-1
  // flushes. If you see size 1 under load, coalescing is being defeated upstream.
  if (DEBUG) console.error(`[openai-proxy] flush batch=${batch.length}`);
  try {
    // One admitted unit for the whole batch — a 429 from admit (shed at admission)
    // propagates to every pending item below.
    const rows = await admit(() => stationEmbedBatch(batch));
    for (let i = 0; i < batch.length; i++) batch[i].resolve(rows[i]);
  } catch (e) {
    // fpost error, 429, or count mismatch: reject every caller in this flush so
    // no one silently gets a wrong/empty vector.
    for (const it of batch) it.reject(e);
  }
}

// Enqueue one tokenized sequence and await its embedding row. Triggers a flush
// when the window elapses (timer armed on the FIRST pending item) or the batch
// hits MAX_BATCH; the size-trigger clears the pending timer so we never double-flush.
function enqueueEmbed(tokens) {
  return new Promise((resolve, reject) => {
    pending.push({ tokens, resolve, reject });
    if (pending.length >= MAX_BATCH) {
      flush(); // size trigger (clears the window timer inside flush)
    } else if (!batchTimer) {
      batchTimer = setTimeout(flush, BATCH_WINDOW_MS);
    }
  });
}

// Tokenize one text and return a real mean-pooled sentence embedding from the
// fat-station forward pass, batched via the coalescer (/hidden-embed-batch: raw
// LE u32 token ids -> LE f32 [hidden_dim] per row). Empty input falls back to a
// single space so the station (which rejects an empty token list) still returns
// a deterministic vector.
// Tokenize one text on the station. Split out from the enqueue so a multi-input
// request can tokenize ALL inputs first and then enqueue them in a single
// synchronous burst — see the /v1/embeddings handler. The station serializes
// /tokenize under its pipeline mutex, so interleaving tokenize+enqueue per item
// (the old `embedText`) spreads the enqueues across that serialized timeline,
// slipping each past the BATCH_WINDOW and defeating the coalescer (every input
// becomes its own forward). Returning { ids, tokens } keeps tokenize separate.
async function tokenizeText(text) {
  let tok;
  try {
    tok = await fpost('/tokenize', { text: text && text.length ? text : ' ' }, TOKENIZE_TIMEOUT_MS);
  } catch (e) {
    // tokenize timed out -> the station is saturated; shed as overloaded (fast 429,
    // client retries) instead of letting it surface as a 500 / a long hang.
    if (e && (e.name === 'TimeoutError' || e.name === 'AbortError')) throw new Overloaded();
    throw e;
  }
  const ids = tok.tokens || [];
  return { ids, tokens: tok.count ?? ids.length };
}

async function embedText(text) {
  const { ids, tokens } = await tokenizeText(text);
  // The cheap /tokenize above stays ungated; the forward is coalesced and admitted.
  const embedding = await enqueueEmbed(ids);
  return { embedding, tokens };
}

function buildPrompt(messages) {
  if (!CHATML) return messages.map((m) => `${m.role}: ${m.content}`).join('\n') + '\nassistant:';
  let s = '';
  for (const m of messages) s += `<|im_start|>${m.role}\n${m.content}<|im_end|>\n`;
  return s + '<|im_start|>assistant\n';
}

function readBody(req) {
  return new Promise((resolve, reject) => {
    let b = '';
    req.on('data', (c) => (b += c));
    req.on('end', () => resolve(b));
    req.on('error', reject);
  });
}

const server = http.createServer(async (req, res) => {
  const json = (code, obj) => { res.writeHead(code, { 'content-type': 'application/json' }); res.end(JSON.stringify(obj)); };
  try {
    if (req.method === 'GET' && (req.url === '/health' || req.url === '/healthz'))
      return json(200, { status: 'ok', model: MODEL, fat_station: FAT });
    if (req.method === 'GET' && req.url === '/v1/models')
      return json(200, { object: 'list', data: [{ id: MODEL, object: 'model', owned_by: 'gnosis' }] });
    if (req.method === 'POST' && (req.url === '/v1/chat/completions' || req.url === '/v1/completions')) {
      if (wouldShed()) throw new Overloaded();
      const reqj = JSON.parse((await readBody(req)) || '{}');
      const messages = reqj.messages || (reqj.prompt ? [{ role: 'user', content: reqj.prompt }] : []);
      const max_tokens = Number(reqj.max_tokens || 256);
      const temperature = Number(reqj.temperature ?? 0);
      const prompt = buildPrompt(messages);
      const tok = await fpost('/tokenize', { text: prompt });
      const gen = await admit(() => fpost('/generate', { tokens: tok.tokens, max_new_tokens: max_tokens, temperature }));
      const det = await fpost('/detokenize', { tokens: gen.generated_tokens });
      let text = det.text || '';
      const cut = text.indexOf('<|im_end|>'); if (cut >= 0) text = text.slice(0, cut);
      return json(200, {
        id: 'chatcmpl-' + Math.random().toString(36).slice(2),
        object: 'chat.completion', created: Math.floor(Date.now() / 1000), model: MODEL,
        choices: [{ index: 0, message: { role: 'assistant', content: text.trimEnd() }, finish_reason: 'stop' }],
        usage: { prompt_tokens: tok.count, completion_tokens: gen.num_new_tokens, total_tokens: tok.count + gen.num_new_tokens },
      });
    }
    if (req.method === 'POST' && req.url === '/v1/embeddings') {
      if (wouldShed()) throw new Overloaded();
      const reqj = JSON.parse((await readBody(req)) || '{}');
      const inputs = Array.isArray(reqj.input)
        ? reqj.input
        : [reqj.input == null ? '' : reqj.input];
      // TWO-PHASE so the inputs actually batch into ONE weight-amortized
      // /hidden-embed-batch forward:
      //   phase 1 — tokenize ALL inputs (the station serializes /tokenize under
      //             its pipeline mutex, so let those round-trips all complete);
      //   phase 2 — enqueue every token sequence in one synchronous burst, so
      //             they are all `pending` together and flush as a single batch.
      // (Interleaving tokenize+enqueue per item — `Promise.all(map(embedText))` —
      // enqueues each row only as its own tokenize resolves; serialized tokenize
      // spreads those enqueues past BATCH_WINDOW_MS, so each input slips into its
      // own batch -> N sequential forwards, the linear "5s for 16" symptom.)
      const toks = await Promise.all(inputs.map((inp) => tokenizeText(String(inp))));
      const embeddings = await Promise.all(toks.map((t) => enqueueEmbed(t.ids)));
      const data = embeddings.map((embedding, i) => ({
        object: 'embedding',
        index: i,
        embedding,
      }));
      const totalTokens = toks.reduce((sum, t) => sum + (t.tokens || 0), 0);
      return json(200, {
        object: 'list',
        data,
        model: MODEL,
        usage: { prompt_tokens: totalTokens, total_tokens: totalTokens },
      });
    }
    json(404, { error: 'not found' });
  } catch (e) {
    // Honest backpressure: the admission gate rejects with 429 when the forward
    // queue is full, instead of letting requests pile onto the station mutex.
    const code = e && e.statusCode === 429 ? 429 : 500;
    if (code === 429) res.setHeader('retry-after', '2');
    json(code, { error: { message: String(e && e.message ? e.message : e), type: code === 429 ? 'overloaded' : 'server_error' } });
  }
});
// Probe the station once at startup: send a 1-sequence /hidden-embed-batch and, if
// it answers with rows (vs 404), auto-engage real batching. This removes the
// remember-the-env-var footgun — pulling the batched fat-station is enough to light
// up the fast path. An explicit PROXY_MAX_BATCH is honored and skips the probe.
async function probeBatchEndpoint() {
  if (MAX_BATCH_ENV != null) {
    console.log(`[openai-proxy] MAX_BATCH=${MAX_BATCH} (pinned via PROXY_MAX_BATCH)`);
    return;
  }
  try {
    const tok = await fpost('/tokenize', { text: 'probe' });
    const ids = (tok.tokens && tok.tokens.length ? tok.tokens : [1]);
    const reply = await fpostBinary('/hidden-embed-batch', packBatch([{ tokens: ids }]));
    if (reply.length > 0) {
      MAX_BATCH = MAX_BATCH_AUTO;
      console.log(`[openai-proxy] /hidden-embed-batch present -> MAX_BATCH=${MAX_BATCH} (auto)`);
    } else {
      console.log(`[openai-proxy] /hidden-embed-batch returned 0 rows -> MAX_BATCH=1 (no batching)`);
    }
  } catch (e) {
    console.log(`[openai-proxy] no /hidden-embed-batch (${String(e && e.message || e)}) -> MAX_BATCH=1`);
  }
}

server.listen(PORT, '0.0.0.0', () => {
  console.log(`[openai-proxy] listening :${PORT} -> ${FAT} (model=${MODEL})`);
  probeBatchEndpoint();
});
